}

async (page) => {
  // Rat is visible at approximately (468, 350) in the screenshot
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 468, y: 350 });
  await page.waitForTimeout(6000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      last_xp: gs.last_xp_event,
      last_combat: gs.last_combat,
      current_target: gs.current_target,
      nearby_mobs: gs.nearby_entities ? gs.nearby_entities.filter(e => e.type === 3 || e.type === 4).slice(0, 5).map(e => ({
        name: e.name, type: e.type, dist: e.distance, hp: e.hp, cx: e.click_x, cy: e.click_y, on_screen: e.on_screen
      })) : []
    });
  });
  return state;
}

